const webhook = $('Webhook').item.json;
const asset = $('Get asset summary').item.json.data[0];
const user = $('Get user').item.json.data[0];
const mileage = $('Car summary').item.json.message.content.mileage;

// Get aggregated NocoBase attachment objects
let attachments = [];
try {
  const aggData = $('Aggregate car info').item.json.attachment;
  if (Array.isArray(aggData)) {
    attachments = aggData;
  }
} catch (e) {
  attachments = [];
}

return [{
  json: {
    data: {
      vehicle: asset.id,
      driver: user.id,
      mileage: mileage || null,
      subject: webhook.body.subject,
      originalTitle: webhook.body.subject || null,
      originalDescription: webhook.body.message || null,
      attachments: attachments
    }
  }
}];

// Combine vision result with upload result
const visionContent = $('Fetch car info').item.json.content;
const uploadData = $json.data || $json;

return [{
  json: {
    content: visionContent,
    attachment: uploadData
  }
}];

// === Listy rozszerzeń ===
const IMAGE_EXT = ['png', 'jpg', 'jpeg', 'gif', 'webp'];
const AUDIO_EXT = ['mp3','wav','m4a','flac','ogg','oga','webm','mp4','mpeg','mpga','aac'];
const VIDEO_EXT = ['mp4', 'webm', 'mov', 'avi', 'mpeg', 'mpg', 'wmv', 'flv', '3gp'];

// === Lista MIME, które traktujemy jak octet-stream ===
const UNKNOWN_MIME = ['application/octet-stream','binary/octet-stream','application/x-binary'];

for (const item of items) {
  if (!item.binary) continue;

  const bin = Object.values(item.binary)[0];
  if (!bin || !bin.fileName) continue;

  const fileName = bin.fileName.toLowerCase();
  const ext = fileName.split('.').pop();

  // === Klasyfikacja logiczna ===
  let type_ok = 0; // 0=unknown, 1=image, 2=audio, 3=video

  if (IMAGE_EXT.includes(ext)) type_ok = 1;
  else if (AUDIO_EXT.includes(ext)) type_ok = 2;
  else if (VIDEO_EXT.includes(ext)) type_ok = 3;

  // === Naprawa MIME type (tylko jeśli nieznany) ===
  if (UNKNOWN_MIME.includes(bin.mimeType)) {
    if (type_ok === 1) {
      bin.mimeType = ext === 'png' ? 'image/png' : 'image/jpeg';
    } else if (type_ok === 2) {
      if (ext === 'wav') bin.mimeType = 'audio/wav';
      else if (ext === 'ogg' || ext === 'oga') bin.mimeType = 'audio/ogg';
      else bin.mimeType = 'audio/mpeg';
    } else if (type_ok === 3) {
      bin.mimeType = ext === 'webm' ? 'video/webm' : 'video/mp4';
    }
  }

  // === Zapisz wynik do JSON ===
  item.json.type_ok = type_ok;
  item.json.file_extension = ext;
  item.json.final_mime = bin.mimeType;
}

return items;
